var N8N = $env.N8N_INTERNAL_URL || 'http://n8n:5678/webhook';
var WEBHOOK_KEY = $env.WEBHOOK_API_KEY || 'dev-webhook-key-genai-mlops';
var baseUrl = $env.N8N_WEBHOOK_URL || 'http://localhost:5678/webhook';

try {
  // Check for per-agent query param: GET /webhook/a2a/agent-card?agent=coder
  var webhookData = $('Agent Card Webhook').first().json;
  var filterAgent = (webhookData.query && webhookData.query.agent) || '';

  if (filterAgent) {
    // Per-agent card
    var resp = await _post(N8N + '/agents', {
      action: 'get', name: filterAgent
    }, { timeout: 10000, headers: { 'X-API-Key': WEBHOOK_KEY } });
    var a = resp.data.agent;
    if (!a) throw new Error('Agent not found');
    var agentTags = (a.tags || []).map(function(t) { return t.replace('domain:', ''); });
    (a.tasks || []).forEach(function(t) { agentTags.push(t.name || t); });
    if (agentTags.length === 0) agentTags = [a.name];
    var perSkills = (a.tasks || []).map(function(t) {
      var tn = t.name || t;
      return { id: a.name + '.' + tn, name: tn.charAt(0).toUpperCase() + tn.slice(1),
        description: t.description || tn + ' task', tags: [tn, a.name],
        inputModes: ['text/plain'], outputModes: ['text/plain'] };
    });
    if (perSkills.length === 0) {
      perSkills.push({ id: a.name, name: a.name.charAt(0).toUpperCase() + a.name.slice(1),
        description: a.description || 'AI agent', tags: agentTags,
        inputModes: ['text/plain'], outputModes: ['text/plain'] });
    }
    return [{ json: {
      protocolVersion: '0.2.5',
      name: a.name.charAt(0).toUpperCase() + a.name.slice(1) + ' Agent',
      description: a.description || 'Specialized AI agent',
      url: baseUrl + '/a2a',
      version: '1.0.0',
      provider: { organization: 'Applied AI Systems', url: 'https://github.com/r-aas' },
      capabilities: { streaming: false, pushNotifications: false, stateTransitionHistory: false },
      defaultInputModes: ['text/plain'], defaultOutputModes: ['text/plain'],
      skills: perSkills,
      securitySchemes: { apiKey: { type: 'apiKey', in: 'header', name: 'X-API-Key' } },
      security: [{ apiKey: [] }]
    }}];
  }

  // Full platform card
  var resp = await _post(N8N + '/agents', {
    action: 'list'
  }, { timeout: 15000, headers: { 'X-API-Key': WEBHOOK_KEY } });

  var agents = resp.data.agents || [];

  var skills = agents.map(function(a) {
    var tags = (a.tags || []).map(function(t) { return t.replace('domain:', ''); });
    (a.tasks || []).forEach(function(t) { tags.push(t.name || t); });
    if (tags.length === 0) tags = [a.name];
    return {
      id: a.name,
      name: a.name.charAt(0).toUpperCase() + a.name.slice(1) + ' Agent',
      description: a.description || 'AI agent',
      tags: tags,
      examples: ['Help me with ' + a.name + ' tasks'],
      inputModes: ['text/plain'],
      outputModes: ['text/plain']
    };
  });

  return [{ json: {
    protocolVersion: '0.2.5',
    name: 'GenAI MLOps Platform',
    description: 'Multi-agent platform with ' + agents.length + ' specialized agents',
    url: baseUrl + '/a2a',
    version: '1.0.0',
    provider: {
      organization: 'Applied AI Systems',
      url: 'https://github.com/r-aas'
    },
    capabilities: {
      streaming: false,
      pushNotifications: false,
      stateTransitionHistory: false
    },
    defaultInputModes: ['text/plain'],
    defaultOutputModes: ['text/plain'],
    skills: skills,
    securitySchemes: {
      apiKey: {
        type: 'apiKey',
        in: 'header',
        name: 'X-API-Key'
      }
    },
    security: [{ apiKey: [] }]
  }}];
} catch(e) {
  return [{ json: {
    protocolVersion: '0.2.5',
    name: 'GenAI MLOps Platform',
    description: 'Multi-agent platform (agent discovery temporarily unavailable)',
    url: baseUrl + '/a2a',
    capabilities: { streaming: false, pushNotifications: false },
    defaultInputModes: ['text/plain'],
    defaultOutputModes: ['text/plain'],
    skills: [],
    security: []
  }}];
}

