var body = $('A2A Endpoint').first().json.body || {};

if (body.jsonrpc !== '2.0' || !body.method) {
  return [{ json: {
    jsonrpc: '2.0',
    id: body.id || null,
    error: { code: -32600, message: 'Invalid Request: must be JSON-RPC 2.0 with method field' }
  }}];
}

var method = body.method;
var params = body.params || {};
var reqId = body.id;
var N8N = $env.N8N_INTERNAL_URL || 'http://n8n:5678/webhook';
var WEBHOOK_KEY = $env.WEBHOOK_API_KEY || 'dev-webhook-key-genai-mlops';

try {

  // ── message/send ──
  if (method === 'message/send') {
    var msg = params.message;
    if (!msg || !msg.parts || msg.parts.length === 0) {
      return [{ json: { jsonrpc: '2.0', id: reqId,
        error: { code: -32602, message: 'Invalid params: message with parts required' } } }];
    }
    var textPart = msg.parts.find(function(p) { return p.kind === 'text' || p.type === 'text'; });
    if (!textPart) {
      return [{ json: { jsonrpc: '2.0', id: reqId,
        error: { code: -32602, message: 'Invalid params: at least one text part required' } } }];
    }
    var userMessage = textPart.text;

    // Determine target agent via skill-based routing or metadata
    var meta = params.metadata || {};
    var agentName = '';
    var taskName = '';

    // Priority 1: metadata.skill (A2A native, e.g. "coder.review")
    if (meta.skill) {
      var skillParts = meta.skill.split('.');
      agentName = skillParts[0];
      if (skillParts.length > 1) taskName = skillParts.slice(1).join('.');
    }
    // Priority 2: metadata.agent_name or skill_id (backward compat)
    if (!agentName) agentName = meta.agent_name || meta.skill_id || 'mcp';

    var contextId = msg.contextId || params.contextId || '';

    var chatBody = { agent_name: agentName, message: userMessage };
    if (taskName) chatBody.task = taskName;
    if (contextId) chatBody.session_id = contextId;
    if (meta.model) chatBody.model = meta.model;
    if (meta.temperature != null) chatBody.temperature = meta.temperature;
    if (meta.provider) chatBody.provider = meta.provider;

    var resp = await _post(N8N + '/chat', chatBody, { timeout: 120000, headers: { 'X-API-Key': WEBHOOK_KEY } });
    var data = resp.data;
    var taskId = data.trace_id || ('task_' + Date.now() + '_' + Math.random().toString(36).substr(2, 4));
    var resultContextId = contextId || data.session_id || taskId;

    return [{ json: {
      jsonrpc: '2.0',
      id: reqId,
      result: {
        id: taskId,
        contextId: resultContextId,
        status: { state: 'completed', timestamp: new Date().toISOString() },
        artifacts: [{
          artifactId: 'art_' + taskId.replace('tr_', ''),
          name: 'response',
          parts: [{ kind: 'text', text: data.response || '' }]
        }],
        metadata: { agent: data.agent, task: data.task || undefined, config: data.config, trace_id: data.trace_id },
        kind: 'task'
      }
    }}];
  }

  // ── tasks/get ──
  if (method === 'tasks/get') {
    var taskId = params.id;
    if (!taskId) {
      return [{ json: { jsonrpc: '2.0', id: reqId,
        error: { code: -32602, message: 'Invalid params: id required' } } }];
    }
    var trace;
    try {
      var trResp = await _post(N8N + '/traces', {
        action: 'get', trace_id: taskId
      }, { timeout: 10000, headers: { 'X-API-Key': WEBHOOK_KEY } });
      trace = trResp.data;
    } catch(trErr) {
      return [{ json: { jsonrpc: '2.0', id: reqId,
        error: { code: -32001, message: 'Task not found', data: { taskId: taskId } } } }];
    }
    if (!trace || trace.error) {
      return [{ json: { jsonrpc: '2.0', id: reqId,
        error: { code: -32001, message: 'Task not found', data: { taskId: taskId } } } }];
    }
    return [{ json: {
      jsonrpc: '2.0', id: reqId,
      result: {
        id: taskId,
        contextId: trace.session_id || taskId,
        status: { state: trace.status === 'ok' ? 'completed' : 'failed', timestamp: trace.timestamp || new Date().toISOString() },
        metadata: trace.tags || {},
        kind: 'task'
      }
    }}];
  }

  // ── tasks/cancel ──
  if (method === 'tasks/cancel') {
    return [{ json: { jsonrpc: '2.0', id: reqId,
      error: { code: -32002, message: 'Task not cancelable: synchronous execution model' } } }];
  }

  // ── agent/authenticatedExtendedCard ──
  if (method === 'agent/authenticatedExtendedCard') {
    var baseUrl = $env.N8N_WEBHOOK_URL || 'http://localhost:5678/webhook';
    var resp = await _post(N8N + '/agents', { action: 'list' }, { timeout: 15000, headers: { 'X-API-Key': WEBHOOK_KEY } });
    var agents = resp.data.agents || [];
    var skills = agents.map(function(a) {
      var tags = (a.tags || []).map(function(t) { return t.replace('domain:', ''); });
      (a.tasks || []).forEach(function(t) { tags.push(t.name || t); });
      if (tags.length === 0) tags = [a.name];
      return {
        id: a.name,
        name: a.name.charAt(0).toUpperCase() + a.name.slice(1) + ' Agent',
        description: a.description || 'AI agent',
        tags: tags,
        inputModes: ['text/plain'],
        outputModes: ['text/plain']
      };
    });
    return [{ json: {
      jsonrpc: '2.0', id: reqId,
      result: {
        protocolVersion: '0.2.5',
        name: 'GenAI MLOps Platform',
        url: baseUrl + '/a2a',
        capabilities: { streaming: false, pushNotifications: false, stateTransitionHistory: false },
        defaultInputModes: ['text/plain'],
        defaultOutputModes: ['text/plain'],
        skills: skills,
        securitySchemes: { apiKey: { type: 'apiKey', in: 'header', name: 'X-API-Key' } },
        security: [{ apiKey: [] }]
      }
    }}];
  }

  // ── Unknown method ──
  return [{ json: {
    jsonrpc: '2.0', id: reqId,
    error: { code: -32601, message: 'Method not found: ' + method }
  }}];

} catch(e) {
  if (e.code && typeof e.code === 'number' && e.message) {
    return [{ json: { jsonrpc: '2.0', id: reqId, error: e } }];
  }
  return [{ json: {
    jsonrpc: '2.0', id: reqId,
    error: { code: -32603, message: 'Internal error: ' + (e.message || String(e)) }
  }}];
}
